function updateMrKowalski(node) {
  if (Array.isArray(node)) return node.map(updateMrKowalski)
  if (node && typeof node === "object") {
    const out = {}
    for (const [k, v] of Object.entries(node)) {
      if (k === "mr_kowalski") {
        if (v && typeof v === "object" && !Array.isArray(v)) {
          out[k] = { ...v, full_name: "John Ronald Kowalski" }
        } else {
          out[k] = { full_name: "John Ronald Kowalski" }
        }
      } else {
        out[k] = updateMrKowalski(v)
      }
    }
    return out
  }
  return node
}

