return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/source",
      value: `const WIDTH = 20;
const HEIGHT = 20;

const COLORS = {
  bg: "#9bbc0f",
  grid: "#8bac0f",
  snake: "#0f380f",
  head: "#306230",
  food: "#0f380f"
};

function drawCell(ctx, x, y, color) {
  ctx.fillStyle = color;
  ctx.fillRect(x, y, 1, 1);
}

function SnakeGame() {
  const canvasRef = React.useRef(null);
  const [snake, setSnake] = React.useState([{ x: 10, y: 10 }]);
  const [dir, setDir] = React.useState({ x: 1, y: 0 });
  const [food, setFood] = React.useState({ x: 5, y: 5 });

  React.useEffect(() => {
    const onKeyDown = (e) => {
      const next =
        e.key === "ArrowUp" ? { x: 0, y: -1 } :
        e.key === "ArrowDown" ? { x: 0, y: 1 } :
        e.key === "ArrowLeft" ? { x: -1, y: 0 } :
        e.key === "ArrowRight" ? { x: 1, y: 0 } : null;
      if (!next) return;
      setDir((cur) => (cur.x + next.x === 0 && cur.y + next.y === 0 ? cur : next));
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, []);

  React.useEffect(() => {
    const id = setInterval(() => {
      setSnake((cur) => {
        const head = cur[0];
        const nextHead = {
          x: (head.x + dir.x + WIDTH) % WIDTH,
          y: (head.y + dir.y + HEIGHT) % HEIGHT
        };
        const nextSnake = [nextHead, ...cur];
        if (nextHead.x === food.x && nextHead.y === food.y) {
          setFood({
            x: Math.floor(Math.random() * WIDTH),
            y: Math.floor(Math.random() * HEIGHT)
          });
          return nextSnake;
        }
        nextSnake.pop();
        return nextSnake;
      });
    }, 140);
    return () => clearInterval(id);
  }, [dir, food]);

  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const scale = 12;
    canvas.width = WIDTH * scale;
    canvas.height = HEIGHT * scale;
    ctx.imageSmoothingEnabled = false;
    ctx.fillStyle = COLORS.bg;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let x = 0; x < WIDTH; x++) {
      for (let y = 0; y < HEIGHT; y++) {
        if ((x + y) % 2 === 0) {
          ctx.fillStyle = COLORS.grid;
          ctx.fillRect(x * scale, y * scale, scale, scale);
        }
      }
    }

    ctx.fillStyle = COLORS.food;
    ctx.fillRect(food.x * scale, food.y * scale, scale, scale);

    snake.forEach((part, i) => {
      ctx.fillStyle = i === 0 ? COLORS.head : COLORS.snake;
      ctx.fillRect(part.x * scale, part.y * scale, scale, scale);
    });
  }, [snake, food]);

  return <canvas ref={canvasRef} style={{ width: "100%", maxWidth: 360, border: "2px solid #0f380f", background: COLORS.bg }} />;
}

return <SnakeGame />`
    }
  ]
})

